// english-content-1.js — Flashcards & Questions for English Topic 1: Vocabulary
// Islands: ei-01-1 through ei-01-9

// ── FLASHCARDS ────────────────────────────────────────────────────────────
FLASHCARDS.push(
  // ── ei-01-1: Prefixes & Suffixes ────────────────────────────────────
  {id:"efc-01-1-1",islandId:"ei-01-1",front:"What does the prefix 'pre-' mean? Give three examples.",
   back:"'Pre-' means BEFORE.\n\nExamples:\n• preview — to view before (e.g. a film preview)\n• predict — to say what will happen before it occurs\n• prevent — to stop something before it happens\n\nKnowing 'pre-' helps you work out the meaning of any new word that starts with it.",difficulty:1,category:"definition"},
  {id:"efc-01-1-2",islandId:"ei-01-1",front:"What is the rule for adding the suffix '-able' vs '-ible' to a root word?",
   back:"Both suffixes mean 'capable of being' or 'able to be', but they attach to different roots:\n\n• -able usually attaches to complete root words (readable, washable, comfortable)\n• -ible usually attaches to Latin roots or words that are not complete English words alone (flexible, terrible, visible)\n\nSpelling tip: if you can hear the root word clearly on its own, try -able first. If the root is not a stand-alone word, use -ible.",difficulty:2,category:"rule"},
  {id:"efc-01-1-3",islandId:"ei-01-1",front:"What does 'misconduct' mean? Use your knowledge of prefixes to explain.",
   back:"Misconduct means wrongful or unacceptable behaviour.\n\nBreak it down:\n• mis- = wrongly / badly\n• conduct = behaviour or the way someone acts\n\nSo misconduct literally means 'behaving wrongly'.\n\nThe prefix mis- appears in many words: mistake (a wrong take/judgement), misunderstand (to understand wrongly), mislead (to lead in the wrong direction).",difficulty:2,category:"application"},

  // ── ei-01-2: Greek & Latin Roots ────────────────────────────────────
  {id:"efc-01-2-1",islandId:"ei-01-2",front:"What does the Latin root 'port' mean? Give four examples of words that contain it.",
   back:"The Latin root 'port' means TO CARRY.\n\nExamples:\n• import — to carry goods into a country\n• export — to carry goods out of a country\n• transport — to carry people or things across a distance\n• portable — capable of being carried\n\nStrategy: spotting a familiar root helps you make an educated guess at the meaning of any new word containing it.",difficulty:1,category:"definition"},
  {id:"efc-01-2-2",islandId:"ei-01-2",front:"What does the Greek root 'bio' mean? Give three examples.",
   back:"The Greek root 'bio' means LIFE.\n\nExamples:\n• biology — the study of living things\n• biography — a written account of someone's life\n• antibiotic — a medicine that works against (anti-) living bacteria\n\nYou will also see it in: biodiversity, biochemistry, biomass.",difficulty:1,category:"definition"},
  {id:"efc-01-2-3",islandId:"ei-01-2",front:"The word 'aquatic' contains the Latin root 'aqua'. What does 'aqua' mean, and how does this help you understand 'aquarium'?",
   back:"'Aqua' is Latin for WATER.\n\n• aquatic — relating to water (aquatic animals live in water)\n• aquarium — a tank filled with water for keeping fish and other aquatic creatures\n\nThe root 'aqua' also appears in:\n• aqueduct — a channel that carries water\n• aquamarine — a blue-green colour like the sea\n\nOnce you know the root, the whole word family becomes easier to remember.",difficulty:2,category:"application"},

  // ── ei-01-3: Synonyms & Antonyms ────────────────────────────────────
  {id:"efc-01-3-1",islandId:"ei-01-3",front:"What is a synonym? Give three pairs of synonyms.",
   back:"A synonym is a word that has the same or very similar meaning to another word.\n\nExamples:\n• happy / joyful\n• begin / start\n• large / huge\n\nNote: synonyms are rarely perfectly identical — they often carry slightly different shades of meaning. For example, 'joyful' suggests a stronger feeling than 'happy'.",difficulty:1,category:"definition"},
  {id:"efc-01-3-2",islandId:"ei-01-3",front:"What is an antonym? Give three pairs of antonyms.",
   back:"An antonym is a word that has the opposite meaning to another word.\n\nExamples:\n• hot / cold\n• brave / cowardly\n• ancient / modern\n\nAntonyms can be formed using prefixes:\n• happy → unhappy\n• possible → impossible\n• honest → dishonest",difficulty:1,category:"definition"},
  {id:"efc-01-3-3",islandId:"ei-01-3",front:"Which is the best synonym for 'eloquent' in the sentence: 'She gave an eloquent speech that moved the audience'?",
   back:"The best synonym is articulate (or fluent).\n\n'Eloquent' means able to express ideas clearly and persuasively in speech or writing.\n\n• articulate — expressing ideas clearly and effectively (best match)\n• fluent — speaking smoothly without hesitation\n\nNot: loud (relates to volume, not quality), long (relates to duration), or scripted (means written out in advance — does not capture the quality of expression).",difficulty:2,category:"application"},

  // ── ei-01-4: Homophones ──────────────────────────────────────────────
  {id:"efc-01-4-1",islandId:"ei-01-4",front:"What is a homophone? Give two well-known examples.",
   back:"A homophone is a word that sounds the same as another word but has a different spelling and a different meaning.\n\nExamples:\n• their / there / they're\n  - their = belonging to them (their books)\n  - there = a place (over there)\n  - they're = they are (they're happy)\n\n• your / you're\n  - your = belonging to you (your coat)\n  - you're = you are (you're late)\n\nTip: if you can replace the word with 'they are' or 'you are', use the apostrophe form.",difficulty:1,category:"rule"},
  {id:"efc-01-4-2",islandId:"ei-01-4",front:"Complete the sentence correctly: 'The students handed in ___ homework.'",
   back:"The correct answer is THEIR.\n\n• their — belonging to them ✓\n• there — a place (over there) ✗\n• they're — they are (they're homework makes no sense) ✗\n\nMemory trick: 'their' contains the word 'heir' (a person who inherits something), reminding you it is about ownership/belonging.",difficulty:1,category:"example"},
  {id:"efc-01-4-3",islandId:"ei-01-4",front:"Which word correctly completes the sentence: 'The loud music will ___ my concentration.'  affect or effect?",
   back:"The correct word is AFFECT.\n\n• affect (verb) — to have an influence on something\n  'The noise will affect my concentration.' ✓\n\n• effect (noun) — the result or outcome\n  'The noise had a negative effect on my concentration.' ✓\n\nMemory trick: Affect is the Action (both start with A). Effect is the End result (both start with E).\n\nIn this sentence, 'will ___' requires a verb → affect.",difficulty:2,category:"application"},

  // ── ei-01-5: Shades of Meaning & Connotation ────────────────────────
  {id:"efc-01-5-1",islandId:"ei-01-5",front:"What is connotation? Show how two words with the same denotation can have different connotations.",
   back:"Connotation is the emotional association or feeling a word carries beyond its literal (dictionary) meaning.\n\nExample — both words mean 'thin':\n• slender — positive connotation (elegant, graceful)\n• scrawny — negative connotation (unhealthily thin, bony)\n\nDenotation is the literal meaning (both = thin).\nConnotation is the emotional colouring (positive vs negative).\n\nAuthors choose words with specific connotations deliberately to influence how readers feel about a character or situation.",difficulty:2,category:"definition"},
  {id:"efc-01-5-2",islandId:"ei-01-5",front:"Order these words from least intense to most intense: boiling, warm, hot, scorching.",
   back:"Least → Most intense:\nwarm → hot → boiling → scorching\n\n• warm: pleasantly heated\n• hot: noticeably high temperature\n• boiling: at or near 100°C, very hot\n• scorching: extremely hot, burning\n\nRecognising degrees of intensity (called gradable synonyms) allows you to choose the most precise word when writing.",difficulty:1,category:"example"},
  {id:"efc-01-5-3",islandId:"ei-01-5",front:"Why might an author choose 'determined' rather than 'stubborn' to describe a hero?",
   back:"Because 'determined' has a positive connotation while 'stubborn' has a negative connotation, even though both describe someone who refuses to give up.\n\n• determined — suggests admirable persistence, strength of will, focus on a goal\n• stubborn — suggests unreasonable inflexibility, refusing to listen to others\n\nAuthors craft our feelings about characters through word choice. Using 'determined' makes the hero seem admirable; using 'stubborn' would make them seem frustrating or difficult.",difficulty:2,category:"application"},

  // ── ei-01-6: Analogies ───────────────────────────────────────────────
  {id:"efc-01-6-1",islandId:"ei-01-6",front:"What is an analogy? Give an example.",
   back:"An analogy is a comparison that shows a relationship between two pairs of words.\n\nExample: 'Puppy is to dog as kitten is to cat.'\n\nThis shows a baby-to-adult-animal relationship. Both pairs follow the same rule.\n\nAnalogies test your ability to:\n1. Identify the relationship in the first pair\n2. Apply that same relationship to find the missing word in the second pair\n\nWritten as: puppy : dog :: kitten : cat",difficulty:1,category:"definition"},
  {id:"efc-01-6-2",islandId:"ei-01-6",front:"Complete the analogy: 'Glove is to hand as shoe is to ___.'",
   back:"Shoe is to FOOT.\n\nRelationship: the first word is something worn ON the second word (clothing/body part relationship).\n\n• Glove → worn on the hand\n• Shoe → worn on the foot\n\nStep 1: identify the relationship (worn on a body part)\nStep 2: apply it to the new pair (shoe is worn on → foot)",difficulty:1,category:"example"},
  {id:"efc-01-6-3",islandId:"ei-01-6",front:"Complete the analogy: 'Author is to book as composer is to ___.'",
   back:"Composer is to SYMPHONY (or MUSIC).\n\nRelationship: the first person creates the second thing — a creator-to-creation relationship.\n\n• Author → creates a book\n• Composer → creates a symphony / musical composition\n\nOther examples of this relationship type:\n• Architect : building :: sculptor : statue\n• Chef : meal :: poet : poem",difficulty:2,category:"application"},

  // ── ei-01-7: Context Clues ───────────────────────────────────────────
  {id:"efc-01-7-1",islandId:"ei-01-7",front:"What are context clues? Name the four main types.",
   back:"Context clues are words and phrases in the surrounding text that help you figure out the meaning of an unfamiliar word.\n\nFour main types:\n1. Definition clue — the text directly defines the word\n2. Synonym clue — a nearby word with a similar meaning\n3. Antonym/contrast clue — a nearby word with the opposite meaning\n4. Example clue — examples given that illustrate the meaning\n\nSignal words to look for: 'or', 'also known as', 'unlike', 'however', 'for example', 'such as'.",difficulty:1,category:"definition"},
  {id:"efc-01-7-2",islandId:"ei-01-7",front:"Identify the context clue type in this sentence: 'The hermit, a person who lives alone and avoids others, rarely left his cave.'",
   back:"This is a DEFINITION clue.\n\nThe phrase 'a person who lives alone and avoids others' directly explains what 'hermit' means. It is placed after a comma, which signals that a definition or explanation follows.\n\nOther signals for definition clues:\n• dashes: The hermit — someone who lives alone — ...\n• parentheses: The hermit (a person who lives alone) ...\n• the phrase 'which means' or 'is defined as'",difficulty:1,category:"rule"},
  {id:"efc-01-7-3",islandId:"ei-01-7",front:"What does 'gregarious' mean in this sentence? 'Unlike her gregarious sister who loved parties, Maya was reserved.'",
   back:"Gregarious means SOCIABLE or OUTGOING.\n\nContext clue type: Antonym/contrast clue.\n\nHow to work it out:\n• The word 'Unlike' signals a contrast between the two sisters\n• Maya is described as 'reserved' (quiet, keeping to herself)\n• The sister is the OPPOSITE of reserved → she must be sociable and outgoing\n• 'loved parties' is additional evidence — gregarious people enjoy social gatherings\n\nTherefore: gregarious = fond of company, sociable.",difficulty:2,category:"application"},

  // ── ei-01-8: Reference Skills ────────────────────────────────────────
  {id:"efc-01-8-1",islandId:"ei-01-8",front:"What are guide words in a dictionary? How do you use them?",
   back:"Guide words are the two words printed at the top of a dictionary page. They show the FIRST and LAST entries on that page.\n\nHow to use them:\n1. Open the dictionary roughly where you think your word will be\n2. Look at the guide words — if your word comes alphabetically between them, it is on that page\n3. If your word comes before the first guide word, flip back; if it comes after the second, flip forward\n\nExample: guide words 'fable' and 'fact' → 'fabric' would appear on this page.",difficulty:1,category:"rule"},
  {id:"efc-01-8-2",islandId:"ei-01-8",front:"What does a thesaurus entry show? When would you use a thesaurus rather than a dictionary?",
   back:"A thesaurus entry shows:\n• The headword (the word you looked up)\n• A list of synonyms — words with similar meanings\n• Sometimes antonyms — words with opposite meanings\n• Sometimes the synonyms are grouped by nuance or context\n\nUse a DICTIONARY when you need to know what a word means.\nUse a THESAURUS when you already know what you want to say but want to find a more precise, varied, or interesting word.\n\nExample: if you keep writing 'said', a thesaurus offers: replied, whispered, announced, insisted.",difficulty:1,category:"definition"},
  {id:"efc-01-8-3",islandId:"ei-01-8",front:"A dictionary page has guide words 'planet' and 'please'. Which of these words appear on the page: play, plant, plead, plum?",
   back:"The words on the page are: plant, plead, and play.\n\nTo check, compare alphabetically between 'planet' and 'please':\n• planet → p-l-a-n-e-t\n• plant → p-l-a-n-t (comes after planet ✓, before please ✓) ON PAGE\n• plead → p-l-e-a-d (comes after planet ✓, before please ✓) ON PAGE\n• play → p-l-a-y (comes after planet ✓, before please ✓) ON PAGE\n• plum → p-l-u (u comes after e in 'please') → NOT on this page\n\nRemember to compare letter by letter from left to right.",difficulty:2,category:"application"},

  // ── ei-01-9: Multiple-Meaning Words ────────────────────────────────────
  {id:"efc-01-9-1",islandId:"ei-01-9",front:"What are multiple-meaning words? Give two examples.",
   back:"Multiple-meaning words (also called homonyms) are words that have more than one definition. They are spelt and pronounced the same way, but their meaning changes depending on context.\n\nExamples:\n• bank — a place that looks after money OR the edge of a river\n• bat — a piece of cricket equipment OR a flying mammal\n• light — brightness OR not heavy\n\nYou must read the surrounding words to work out which meaning is being used.",difficulty:1,category:"definition"},
  {id:"efc-01-9-2",islandId:"ei-01-9",front:"How do you work out which meaning of a multiple-meaning word is being used in a sentence?",
   back:"Use these four steps:\n\n1. Read the whole sentence (and the sentences around it).\n2. Look for context clues — other words that point towards one meaning.\n3. Try each meaning in the sentence and see which one makes sense.\n4. Check the part of speech — is the word a noun, verb, or adjective? This often narrows it down.\n\nExample: 'She picked up the bat and walked to the crease.'\nContext clues: 'crease' is a cricket term → bat = cricket bat, not an animal.",difficulty:1,category:"concept"},
  {id:"efc-01-9-3",islandId:"ei-01-9",front:"What is the difference between multiple-meaning words and homophones?",
   back:"Multiple-meaning words (homonyms) are the SAME word with different definitions.\n• 'fair' (adjective: just) and 'fair' (noun: funfair) — same spelling, same pronunciation.\n\nHomophones are DIFFERENT words that sound the same but are spelt differently.\n• 'their' / 'there' / 'they're' — different spellings and meanings.\n• 'flour' / 'flower' — different spellings and meanings.\n\nKey distinction: multiple-meaning words share the same spelling; homophones do not.",difficulty:2,category:"concept"},
  {id:"efc-01-9-4",islandId:"ei-01-9",front:"In the sentence 'The trunk was too heavy to lift', how do you decide which meaning of 'trunk' is intended?",
   back:"On its own, this sentence is ambiguous — 'trunk' could mean:\n• the main stem of a tree\n• a large storage box or suitcase\n• the boot of a car\n• an elephant's nose\n\nYou would need MORE context to be certain. For example:\n• 'The trunk was too heavy to lift onto the luggage rack.' → a large box/suitcase\n• 'The trunk was too heavy to lift — years of growth had made the oak enormous.' → tree trunk\n\nThis shows why context is essential. Without it, the meaning remains unclear.",difficulty:2,category:"application"}
);

